import { MakeLogicType, actions, afterMount, kea, key, listeners, path, props, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'

import { CyclotronJobInputType, HogFunctionTemplateType } from '~/types'

import { HogFlowActionTemplateApi } from '../generated/api.schemas'
import { actionTemplatesLogic } from '../Workflows/hogflows/actionTemplatesLogic'

export interface ActionTemplateEditorLogicProps {
    actionTemplate: HogFlowActionTemplateApi
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface actionTemplateEditorLogicValues {
    catalogTemplate: HogFunctionTemplateType | null
    catalogTemplateLoading: boolean
    description: string
    inputs: Record<string, CyclotronJobInputType>
    name: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface actionTemplateEditorLogicActions {
    loadCatalogTemplate: () => any
    loadCatalogTemplateFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadCatalogTemplateSuccess: (
        catalogTemplate: HogFunctionTemplateType,
        payload?: any
    ) => {
        catalogTemplate: HogFunctionTemplateType
        payload?: any
    }
    save: () => {
        value: true
    }
    setDescription: (description: string) => {
        description: string
    }
    setInput: (
        key: string,
        input: CyclotronJobInputType
    ) => {
        input: {
            bytecode?: any
            order?: number | undefined
            secret?: boolean | undefined
            templating?: 'hog' | 'liquid' | undefined
            value: any
        }
        key: string
    }
    setName: (name: string) => {
        name: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface actionTemplateEditorLogicMeta {
    key: string
}

export type actionTemplateEditorLogicType = MakeLogicType<
    actionTemplateEditorLogicValues,
    actionTemplateEditorLogicActions,
    ActionTemplateEditorLogicProps,
    actionTemplateEditorLogicMeta
>

export const actionTemplateEditorLogic = kea<actionTemplateEditorLogicType>([
    props({} as ActionTemplateEditorLogicProps),
    key((props) => props.actionTemplate.id),
    path((key) => ['products', 'workflows', 'frontend', 'library', 'actionTemplateEditorLogic', key]),
    actions({
        setName: (name: string) => ({ name }),
        setDescription: (description: string) => ({ description }),
        setInput: (key: string, input: CyclotronJobInputType) => ({ key, input }),
        save: true,
    }),
    reducers(({ props }) => ({
        name: [props.actionTemplate.name, { setName: (_, { name }) => name }],
        description: [props.actionTemplate.description ?? '', { setDescription: (_, { description }) => description }],
        inputs: [
            (props.actionTemplate.inputs ?? {}) as Record<string, CyclotronJobInputType>,
            { setInput: (state, { key, input }) => ({ ...state, [key]: input }) },
        ],
    })),
    loaders(({ props }) => ({
        catalogTemplate: [
            null as HogFunctionTemplateType | null,
            {
                loadCatalogTemplate: async () => {
                    return await api.hogFunctions.getTemplate(props.actionTemplate.template_id)
                },
            },
        ],
    })),
    listeners(({ values, props }) => ({
        save: () => {
            actionTemplatesLogic.actions.updateActionTemplate({
                id: props.actionTemplate.id,
                template: {
                    name: values.name,
                    description: values.description,
                    inputs: values.inputs as any,
                },
            })
        },
    })),
    afterMount(({ actions }) => {
        actions.loadCatalogTemplate()
    }),
])
